import { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import axios from "axios";

const ResetPassword = () => {
  const [newPassword, setNewPassword] = useState("");
  const [confirmPassword, setConfirmPassword] = useState("");
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");
  const navigate = useNavigate();

  const email = localStorage.getItem("resetEmail");

  useEffect(() => {
    if (!localStorage.getItem("otpVerified") || !email) {
      navigate("/forgot-password"); // Redirect if OTP is not verified
    }
  }, [navigate, email]);

  const handleResetPassword = async () => {
    if (!newPassword || !confirmPassword) {
      setError("All fields are required!");
      return;
    }

    if (newPassword !== confirmPassword) {
      setError("Passwords do not match!");
      return;
    }

    try {
      const response = await axios.post("http://localhost:5000/api/auth/reset-password", { email, newPassword });

      setSuccess(response.data.message);
      localStorage.removeItem("otpVerified"); // Remove OTP verification flag
      localStorage.removeItem("resetEmail"); // Remove email
      setTimeout(() => navigate("/"), 2000); // Redirect to login
    } catch (error) {
      setError(error.response?.data?.message || "Password reset failed.");
    }
  };

  return (
    <div>
      <h2>Reset Password</h2>
      <input type="password" placeholder="New Password" value={newPassword} onChange={(e) => setNewPassword(e.target.value)} />
      <input type="password" placeholder="Confirm Password" value={confirmPassword} onChange={(e) => setConfirmPassword(e.target.value)} />
      <button onClick={handleResetPassword}>Reset Password</button>
      {error && <p style={{ color: "red" }}>{error}</p>}
      {success && <p style={{ color: "green" }}>{success}</p>}
    </div>
  );
};

export default ResetPassword;
